import { Button, Grid, Row, Text } from "@nextui-org/react";
import React, { useState } from "react";
import InfoCard from "../Components/InfoCard";
import confetti from "canvas-confetti";
import SocialCard from "../Components/SocialCard";

export default function ContactSection(props: any) {
  const handleConfetti = () => {
    confetti({
      particleCount: 150,
      spread: 360,
      origin: {
        x: Math.random(),
        // since they fall down, start a bit higher than random
        y: Math.random() - 0.2,
      },
    });
  };

  return (
    <section id="contact">
      <Row justify="center" align="center" css={{ mt: "80px" }}>
        <Text h6>Get In Touch</Text>
      </Row>
      <Row justify="center" align="center">
        <Text
          h5
          css={{
            textGradient: "45deg, $pink600 -20%, $purple600 100%",
          }}
          weight="bold"
        >
          Contact Me
        </Text>
      </Row>
      <Grid.Container gap={2} css={{ mt: "50px" }}>
        <Grid xs={4} sm={6}>
          <Grid.Container gap={2} alignItems="flex-end" direction="column">
            <Grid sm={4}>
              <SocialCard ic={1} title="saadamir.m@gmail.com" />
            </Grid>
            <Grid sm={4}>
              <SocialCard ic={2} title="/in/saad-amir" />
            </Grid>
            <Grid sm={4}>
              <SocialCard ic={3} title="@saadamirpk" />
            </Grid>
          </Grid.Container>
        </Grid>
      </Grid.Container>
    </section>
  );
}
